+		t.Fatalf("unexpected error: %v", err)
+	}
+	if len(steps) != 1 {
+		t.Fatalf("expected 1 step, got %d", len(steps))
+	}
+
+	// Ref preserves original (though trimmed)
+	if steps[0].Ref != "spaced" {
